{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a complex optimization task involving spatial reasoning, probabilistic modeling, and cost minimization. I will break it down into geometric modeling, query strategy optimization, and final state estimation.",
  "helpers": [
    {
      "label": "geometric_modeler",
      "instructions": "Represent the known polyomino shapes as sets of relative coordinates. For each shape, define its bounding box and all possible valid translations within the grid constraints. Create a function that, given a set of probed cells, calculates the intersection of all possible polyomino placements that are consistent with the observed data."
    },
    {
      "label": "query_optimizer",
      "instructions": "Develop a strategy to minimize probing cost. Given the current knowledge of possible polyomino locations and the noise model of the aggregate queries, calculate the expected information gain (entropy reduction) for different types of probes (drilling vs. aggregate queries). Propose the next best probe that maximizes information gain per unit of cost."
    },
    {
      "label": "probabilistic_estimator",
      "instructions": "Given a sequence of noisy aggregate query results and specific drilling results, use a Bayesian approach to update the probability distribution of each cell being part of an oil-containing polyomino. Account for the noise in the aggregate queries to provide a confidence score for each cell."
    }
  ],
  "synthesis_brief": "The geometric_modeler provides the search space of valid shapes. The query_optimizer uses this space to suggest the most efficient sequence of probes. The probabilistic_estimator processes the results of those probes to refine the likelihood of oil presence. The final solution will be the set of cells with the highest posterior probability of containing oil, selected to minimize the total cost incurred during the probing phase."
}

